    const sanitizedHtml = DOMPurify.sanitize(html);

    // Apply highlighting if search term is provided
    if (searchTerm && searchTerm.trim()) {
      return highlightText(sanitizedHtml, searchTerm);
    }

    return sanitizedHtml;
  } catch (error) {
    console.error('Markdown parsing error:', error);
    const fallbackHtml = markdown.replace(/\n/g, '<br>');
    const sanitizedFallback = DOMPurify.sanitize(fallbackHtml);

    if (searchTerm && searchTerm.trim()) {
      return highlightText(sanitizedFallback, searchTerm);
    }

    return sanitizedFallback;
  }
